onClick:
{{
  getActivityHistoryAll.run(() => {
    const rows = getActivityHistoryAll.data;

    if (Array.isArray(rows) && rows.length > 0) {
      // Get headers from keys of the first row
      const headers = Object.keys(rows[0]);

      // Build CSV rows
      const csvRows = [
        headers.join(","), // header row
        ...rows.map(row => 
          headers.map(field => {
            const value = row[field] ?? "";
            // Escape quotes and wrap in double quotes if needed
            const escaped = String(value).replace(/"/g, '""');
            return `"${escaped}"`;
          }).join(",")
        )
      ];

      // Join rows with newlines
      const csvData = csvRows.join("\n");

      // Trigger CSV download
      download(csvData, "ActivityHistory_All.csv", "text/csv");
      showAlert("✅ Export completed successfully!", "success");
    } else {
      showAlert("⚠️ No records found to export.", "warning");
    }
  });
}}
